const users = $input.all();
const interestsSet = new Set();

users.forEach(user => {
  const raw = user.json.interests;
  if (!raw || typeof raw !== 'string') return;

  // Split by comma, clean each item, add to set
  raw.split(',').forEach(item => {
    const trimmed = item.trim().toLowerCase();
    if (trimmed) {
      interestsSet.add(trimmed);
    }
  });
});

// Return one item per unique interest for the Loop Over Items node
const uniqueInterests = Array.from(interestsSet);
return uniqueInterests.map(interest => ({
  json: { interest: interest }
}));

const rssItems = $input.all();
const rawData = $('Edit Fields4').first().json; 

return rssItems.map(item => {
  const rss = item.json;

  return {
    json: {
      interest: rawData.interest,  
      title: rss.title,
      articles: rss.content,
      cache_date: new Date().toISOString().split('T')[0],
      url: rss.link
    }
  };
});

const editFields  = $('Map Fields').first().json;
const aiOutput    = $input.first().json.output;

let todolist = "You don't have anything scheduled for today. Enjoy!";
let trends   = "Add interests to get personalized trends!";

try {
  const cleaned = aiOutput.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  const parsed  = JSON.parse(cleaned);

  if (parsed.todo_block && parsed.todo_block.trim().length > 0) {
    todolist = parsed.todo_block;
  }
  if (parsed.trends_block && parsed.trends_block.trim().length > 0) {
    trends = parsed.trends_block;
  }
} catch (e) {
  // Falls back to defaults
}

return {
  json: {
    phone_no:  editFields.phone_no,
    name:     editFields.user_name,
    todolist: todolist,
    trends:   trends,
    telegram_id: editFields.telegram_id
  }
};

